class Solution {
public:
    string shortestPalindrome(string s) {
        string reversed = s;
        reverse(reversed.begin(), reversed.end());
        string longestCommonPrefix = "";
        for (int i = 0; i < s.size() && i < reversed.size(); i++) {
            if (s[i] == reversed[i]) {
                longestCommonPrefix += s[i];
            } else {
                break;
            }
        }
        return reversed + longestCommonPrefix;
    }
};
